import{_ as a,c as t,o as l,ag as i}from"./chunks/framework.S-Qvb3wi.js";const g=JSON.parse('{"title":"x402 API","description":"","frontmatter":{"title":"x402 API","aside":false,"outline":false},"headers":[],"relativePath":"zh-TW/x402.md","filePath":"zh-TW/x402.md"}'),o={name:"zh-TW/x402.md"};function r(n,e,s,d,p,c){return l(),t("div",null,e[0]||(e[0]=[i('<h1 id="x402-api" tabindex="-1">x402 API <a class="header-anchor" href="#x402-api" aria-label="Permalink to &quot;x402 API&quot;">​</a></h1><p><strong>DGrid x402 API</strong> 是 DGrid 提供的按次支付模型推理方式。開發者或智能代理不需要先註冊帳號、預先充值或管理獨立計費流程，而是可以直接在 API 請求流程中，透過 <strong>x402 支付協議</strong> 同步完成 LLM 推理費用支付。</p><p>這讓 x402 特別適合以下場景：</p><ul><li><strong>Agent 與自動化工作流</strong>，需要一邊調用模型、一邊即時完成付款</li><li><strong>伺服器端工具與腳本</strong>，不希望再額外處理帳號開通與充值流程</li><li><strong>按需整合</strong>，希望以「發起推理、授權付款、取得結果」的最短路徑接入能力</li></ul><h2 id="為什麼-x402-很重要" tabindex="-1">為什麼 x402 很重要 <a class="header-anchor" href="#為什麼-x402-很重要" aria-label="Permalink to &quot;為什麼 x402 很重要&quot;">​</a></h2><p>傳統 AI 計費流程通常需要：</p><ul><li>建立供應商帳號</li><li>預先充值餘額或綁定支付方式</li><li>管理 API 金鑰、配額與計費後台</li></ul><p>而在 DGrid 的 x402 模式下，流程更直接：</p><blockquote><p>發起推理請求 → 收到付款要求 → 簽名授權 → 帶付款資訊重新請求並取得結果</p></blockquote><p>對 agent 系統來說，這大幅簡化了推理調用。做出模型調用決策的同一個 runtime，也能在同一流程中完成付款授權與結算，而不需要跳入額外的帳號管理流程。</p><h2 id="主要應用場景-agent-直接支付推理費用" tabindex="-1">主要應用場景：Agent 直接支付推理費用 <a class="header-anchor" href="#主要應用場景-agent-直接支付推理費用" aria-label="Permalink to &quot;主要應用場景：Agent 直接支付推理費用&quot;">​</a></h2><p>x402 主要面向這類需求：</p><ol><li>Agent 選擇模型</li><li>Agent 發起推理 API 請求</li><li>Agent 完成該次推理付款</li><li>Agent 使用回傳結果繼續執行任務</li></ol><p>這對以下場景很有價值：</p><ul><li>後端工作流中的 AI Agent</li><li>需要具備支付感知能力的 Web3 Agent 或鏈上協議</li><li>希望將推理視為可直接結算資源的多步驟自動化流程</li></ul><h2 id="流程如何運作" tabindex="-1">流程如何運作 <a class="header-anchor" href="#流程如何運作" aria-label="Permalink to &quot;流程如何運作&quot;">​</a></h2><p>DGrid 的 x402 使用 <strong>兩步式請求流程</strong>：</p><ol><li><strong>第一次請求不帶 <code>x-payment</code></strong> 服務端返回 <code>402 Payment Required</code> 與可簽名的 payment requirements。</li><li><strong>客戶端簽名後重新請求</strong> 客戶端生成 <code>x-payment</code> 載荷，並攜帶該標頭再次發送相同推理請求。</li></ol><p>這種模式使付款授權保持明確，同時仍然讓整個推理調用維持簡單且適合自動化。</p><h2 id="支援的支付資產" tabindex="-1">支援的支付資產 <a class="header-anchor" href="#支援的支付資產" aria-label="Permalink to &quot;支援的支付資產&quot;">​</a></h2><p>目前 x402 端點使用：</p><ul><li><strong>協議</strong>：x402</li><li><strong>網路</strong>：<code>eip155:56</code>（BSC）</li><li><strong>支付代幣</strong>：<code>USD1</code></li><li><strong>資產合約</strong>：<code>0x8d0D000Ee44948FC98c9B98A4FA4921476f08B0d</code></li></ul><h2 id="api-參考" tabindex="-1">API 參考 <a class="header-anchor" href="#api-參考" aria-label="Permalink to &quot;API 參考&quot;">​</a></h2><p>端點級 API 內容已拆分到 x402 API 底下的獨立子頁 <a href="/zh-TW/x402-api-reference">API Reference</a>。</p><p>x402 獨有的部分在於 <strong>支付握手流程</strong>：先請求端點、收到 <code>402 Payment Required</code>，再帶著簽名後的 <code>x-payment</code> 標頭重送同一筆推理請求。</p><p>至於模型調用格式、payload 慣例與供應商風格範例，也可直接參考 DGrid <strong>Model API</strong>：</p><ul><li><a href="/zh-TW/Model-API-Chat#chat-completions">OpenAI 相容 Chat Completions</a></li><li><a href="/zh-TW/Model-API-Chat#native-claude-format">Claude 相容 Messages API</a></li></ul><p>上述頁面涵蓋標準 OpenAI 風格與 Claude 風格的請求格式；x402 的 API Reference 則專注在支付封裝與此端點實際暴露的共用推理欄位。</p><h2 id="運維補充" tabindex="-1">運維補充 <a class="header-anchor" href="#運維補充" aria-label="Permalink to &quot;運維補充&quot;">​</a></h2><p>結算成功後，服務端會將付款記錄寫入後端的 <code>x402_payment_logs</code> 表。</p><h2 id="何時使用-x402-何時使用-ai-gateway" tabindex="-1">何時使用 x402，何時使用 AI Gateway <a class="header-anchor" href="#何時使用-x402-何時使用-ai-gateway" aria-label="Permalink to &quot;何時使用 x402，何時使用 AI Gateway&quot;">​</a></h2><p>若您需要以下能力，請使用 <strong>AI Gateway</strong>：</p><ul><li>傳統 API Key 存取方式</li><li>統一帳戶型模型路由</li><li>標準帳戶計費的長期產品整合</li></ul><p>若您更需要以下能力，請使用 <strong>x402</strong>：</p><ul><li>請求級別的直接付款</li><li>無需預充值帳戶餘額</li><li>讓 agent 在同一流程中完成推理與支付</li></ul>',35)]))}const x=a(o,[["render",r]]);export{g as __pageData,x as default};
